newBlockTasks.truthCssReference:
.forge-topbar img, .forge-topbar video, .forge-topbar svg, .forge-topbar picture {max-width:100%;height:auto}

.forge-topbar main {width:100%}

.forge-topbar .section-inner {max-width:2160px;margin:0 auto}

.forge-topbar .t-title {font-family:var(--font-family-adobe-clean,"Adobe Clean"),sans-serif;font-size:28px;line-height:35px;font-weight:700;text-align:center;color:var(--color-2c2c2c,#2c2c2c);margin:0}

.forge-topbar .t-btn {font-family:var(--font-family-adobe-clean,"Adobe Clean"),sans-serif;font-size:14px;line-height:18px;font-weight:500;text-align:left}

.forge-topbar {padding:0}

.forge-topbar {min-height:160px}

.forge-topbar .topbar-bar {display:flex;justify-content:center;align-items:center;gap:64px;width:100%;height:80px;background:var(--palette-gray-50,#f8f8f8);border-radius:16px}

.forge-topbar .tabs {display:flex;gap:16px}

.forge-topbar .btn {position:relative;display:inline-flex;align-items:center;height:32px;padding:6px 12px 8px 12px;border-radius:8px;background:var(--color-e9e9e9,#e9e9e9);color:var(--color-292929,#292929);white-space:nowrap}

.forge-topbar .btn--active {background:var(--color-292929,#292929);color:#ffffff}

.forge-topbar .btn::after {content:"";position:absolute;right:2px;bottom:2px;width:0;height:0;border-bottom:5px solid currentColor;border-left:5px solid transparent}

@media (max-width:1023px) {
.forge-topbar .topbar-bar {gap:32px;height:auto;padding:16px;flex-wrap:wrap}
.forge-topbar {min-height:0}
.forge-topbar .tabs {flex-wrap:wrap;justify-content:center}
}

@media (max-width:767px) {
.forge-topbar .topbar-bar {flex-direction:column}
.forge-topbar .t-title {font-size:22px;line-height:28px}
}

